/// <summary>
/// Évaluateur de Non-Linéarité (NL) via Walsh-Hadamard Transform.
/// NL = 2^(n-1) - (1/2) · max_{a,b} |Ŝ(a,b)|
/// Référence : Carlet (2010), Boolean functions for cryptography.
/// Valeur cible : NL ≥ 100. AES : NL = 112. Maximum théorique : 128.
/// </summary>

/// <summary>
/// Évaluateur SAC (Strict Avalanche Criterion).
/// ∀ bit_i ∈ {0..7}, ∀ bit_j ∈ {0..7} :
/// P[S(x)_j ≠ S(x ⊕ e_i)_j] = 0.5
/// Référence : Webster & Tavares, CRYPTO'85.
/// Déviation cible : &lt; 0.05. AES : ≈ 0.002.
/// </summary>

/// <summary>
/// Évaluateur de Differential Uniformity (DU).
/// DU = max_{Δx≠0, Δy} |{x : S(x⊕Δx) ⊕ S(x) = Δy}|
/// Référence : Nyberg, K. (1993). EUROCRYPT'93.
/// Valeur cible : DU ≤ 8. AES : DU = 4 (optimal pour n=8).
/// </summary>

/// <summary>
/// Évaluateur de Degré Algébrique (AD) via transform de Möbius.
/// Représentation en Forme Normale Algébrique (ANF) sur GF(2).
/// Référence : Meier & Staffelbach (1989). EUROCRYPT'89.
/// Valeur cible : AD = 7. AES : AD = 7.
/// </summary>

/// <summary>
/// Évaluateur BIC (Bit Independence Criterion).
/// ∀ i ∈ {0..7}, ∀ j≠k ∈ {0..7} : corrélation(Δf_j, Δf_k) ≈ 0
/// Référence : Adams & Tavares (1990). J. Cryptology.
/// Valeur cible : BIC ≥ 0.80. AES : ≈ 0.98.
/// </summary>

/// <summary>
/// Agrégateur fitness composite.
/// F(S) = w₁·NL/NL_max + w₂·(1−SAC/0.5) + w₃·(1−(DU−4)/60) + w₄·AD/7 + w₅·BIC
/// Les poids sont eux-mêmes soumis à méta-évolution (OP_META_WEIGHTS).
/// </summary>

/// <summary>
/// Moteur évolutif principal (μ+λ avec élitisme).
/// Sélection : tournoi k=3.
/// Mutation : swap de paires (préserve bijectivité).
/// Élitisme : top 10% préservés à chaque génération.
/// Transposons : TP_CROSSOVER (8%), TP_POPULATION_RESET (sur stagnation).
/// </summary>

/// <summary>
/// Exporteur de S-Box optimisée.
/// Produit : sbox.cs (C# intégrable), sbox_report.json (audit formel),
/// sbox.hex (dump lisible), sbox_inverse.cs (table de déchiffrement).
/// Déclenché par OP_EXPORT (fitness ≥ fitness_target).
/// </summary>

/// <summary>
/// Méta-évolution des poids fitness.
/// Algorithme : hill-climbing sur l'espace des poids (mutation + évaluation comparative).
/// Déclenché tous les 50 générations (OP_META_WEIGHTS).
/// Permet au protéome de rééquilibrer ses critères d'optimisation au fil de l'évolution.
/// </summary>
